sql:
SELECT name
FROM legal_subjects
WHERE status = 'active';

SELECT COUNT(*) AS total_root_subjects
FROM legal_subjects
WHERE parent_id IS NULL;

SELECT status, COUNT(*) AS subject_count
FROM legal_subjects
GROUP BY status;

SELECT COUNT(*) AS active_subjects_count
FROM legal_subjects
WHERE status = 'active' AND is_deleted = 0;

SELECT COUNT(*) 
FROM legal_subject_types 
WHERE is_deleted = 0;

SELECT definition
FROM legal_subject_types
WHERE status = 'active';

SELECT subject_id, MAX(access_date) AS latest_access_date
FROM subject_access
GROUP BY subject_id;

SELECT subject_id, version_number
FROM subject_versions
WHERE is_current = 1;

SELECT definition_text, created_by
FROM definitions
WHERE definition_id = 0;

SELECT user_id, access_type
FROM subject_access
WHERE access_date = '2023-05-01';
